import{_ as r,o as a,c as l,ag as i}from"./chunks/framework.C6K0jwmI.js";const u=JSON.parse('{"title":"Part 7 — 契約・お支払い","description":"","frontmatter":{"title":"Part 7 — 契約・お支払い","audience":"オーナーのみ","prerequisite":"Part 0 + Part 6","last_updated":"2026-04-18T00:00:00.000Z"},"headers":[],"relativePath":"operations/part7-billing.md","filePath":"operations/part7-billing.md"}'),o={name:"operations/part7-billing.md"};function e(d,t,n,s,h,p){return a(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="part-7-—-契約・お支払い" tabindex="-1">Part 7 — 契約・お支払い <a class="header-anchor" href="#part-7-—-契約・お支払い" aria-label="Permalink to &quot;Part 7 — 契約・お支払い&quot;">​</a></h1><p>このページでは、POSLA の月額料金契約・アドオン追加・解約の方法を、<strong>ボタンの押し方 1 つずつ</strong> 順番に説明します。</p><div class="tip custom-block"><p class="custom-block-title">対象者</p><p>このページはすべて <strong>オーナー（owner）ロール専用</strong> です。マネージャー・スタッフは契約・決済の操作はできません。</p></div><hr><h2 id="_7-0-posla-の料金体系" tabindex="-1">7-0. POSLA の料金体系 <a class="header-anchor" href="#_7-0-posla-の料金体系" aria-label="Permalink to &quot;7-0. POSLA の料金体系&quot;">​</a></h2><h3 id="_7-0-1-単一プラン-アドオン" tabindex="-1">7-0-1. 単一プラン + アドオン <a class="header-anchor" href="#_7-0-1-単一プラン-アドオン" aria-label="Permalink to &quot;7-0-1. 単一プラン + アドオン&quot;">​</a></h3><p>POSLA は <strong>基本料金 + 必要なアドオン</strong> の構成です。通常の店舗運用に必要な機能は基本料金内で利用できます。複数店舗をまとめて運用する場合は、店舗数や本部一括配信アドオンの有無で月額が変わります。</p><table tabindex="0"><thead><tr><th>項目</th><th>金額</th></tr></thead><tbody><tr><td><strong>基本料金（1 店舗目）</strong></td><td>¥20,000 / 月</td></tr><tr><td><strong>追加店舗（2 店舗目以降）</strong></td><td>¥17,000 / 月 / 店舗（1 店舗目から 15% 引き）</td></tr><tr><td><strong>本部一括メニュー配信アドオン</strong></td><td>+¥3,000 / 月 / 店舗（任意）</td></tr><tr><td><strong>トライアル</strong></td><td>初回 30 日間無料（Stripe カード登録必須）</td></tr></tbody></table><h3 id="_7-0-2-料金計算例" tabindex="-1">7-0-2. 料金計算例 <a class="header-anchor" href="#_7-0-2-料金計算例" aria-label="Permalink to &quot;7-0-2. 料金計算例&quot;">​</a></h3><table tabindex="0"><thead><tr><th>構成</th><th>計算</th><th>月額合計</th></tr></thead><tbody><tr><td>1 店舗のみ</td><td>¥20,000</td><td>¥20,000</td></tr><tr><td>2 店舗</td><td>¥20,000 + ¥17,000</td><td>¥37,000</td></tr><tr><td>3 店舗</td><td>¥20,000 + ¥17,000 × 2</td><td>¥54,000</td></tr><tr><td>3 店舗 + アドオン</td><td>¥54,000 + ¥3,000 × 3</td><td>¥63,000</td></tr><tr><td>5 店舗</td><td>¥20,000 + ¥17,000 × 4</td><td>¥88,000</td></tr><tr><td>5 店舗 + アドオン</td><td>¥88,000 + ¥3,000 × 5</td><td>¥103,000</td></tr><tr><td>10 店舗 + アドオン</td><td>¥173,000 + ¥30,000</td><td>¥203,000</td></tr></tbody></table><h3 id="_7-0-3-全機能が標準提供" tabindex="-1">7-0-3. 全機能が標準提供 <a class="header-anchor" href="#_7-0-3-全機能が標準提供" aria-label="Permalink to &quot;7-0-3. 全機能が標準提供&quot;">​</a></h3><p>基本料金を払っている限り、以下はすべて利用可能（アドオン契約の有無に関わらず）:</p><ul><li>セルフオーダー・KDS・ハンディPOS・POSレジ</li><li>Stripe Terminal カード決済・QR 決済</li><li>予約管理・テイクアウト・多言語</li><li>在庫・レシピ・AI 需要予測</li><li>シフト管理・勤怠連携・AI シフト提案</li><li>全レポート（売上・ABC 分析・回転率・スタッフ評価・併売分析）</li><li>クロス店舗分析・統合シフトビュー</li><li>監査ログ・セキュリティ機能</li></ul><h3 id="_7-0-4-本部一括配信アドオンを契約する理由" tabindex="-1">7-0-4. 本部一括配信アドオンを契約する理由 <a class="header-anchor" href="#_7-0-4-本部一括配信アドオンを契約する理由" aria-label="Permalink to &quot;7-0-4. 本部一括配信アドオンを契約する理由&quot;">​</a></h3><p>アドオン契約時のみ:</p><ul><li>オーナー管理画面に <strong>【本部メニュー】</strong> タブが出現</li><li>本部マスタのメニューを owner 側で一括編集</li><li>店舗側ダッシュボードでは本部マスタ項目を店舗ごとに変更できない状態になる</li><li>メニュー変更が全店舗に自動配信される</li></ul><p><strong>想定ユーザー</strong>: 5 店舗以上のチェーン本部、本部で統一メニュー管理したい企業。</p><hr><h2 id="_7-1-サブスクリプション-月額契約-の開始" tabindex="-1">7-1. サブスクリプション（月額契約）の開始 <a class="header-anchor" href="#_7-1-サブスクリプション-月額契約-の開始" aria-label="Permalink to &quot;7-1. サブスクリプション（月額契約）の開始&quot;">​</a></h2><h3 id="_7-1-1-新規申込のフロー" tabindex="-1">7-1-1. 新規申込のフロー <a class="header-anchor" href="#_7-1-1-新規申込のフロー" aria-label="Permalink to &quot;7-1-1. 新規申込のフロー&quot;">​</a></h3><ol><li>POSLA の LP（ランディングページ）を開く <ul><li><code>https://eat.posla.jp/public/</code></li></ul></li><li><strong>【30 日無料で始める】</strong> ボタン</li><li>サインアップフォームに入力:</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>必須</th><th>説明</th></tr></thead><tbody><tr><td>企業名 (屋号)</td><td>✅</td><td>法人名 / 屋号（例: 株式会社○○ / 松の屋）</td></tr><tr><td>1 店舗目の店舗名</td><td>✅</td><td>1 店舗目の名称（例: 渋谷店 / 本店）</td></tr><tr><td>代表者名</td><td>✅</td><td>オーナー氏名</td></tr><tr><td>電話</td><td>✅</td><td>連絡先電話</td></tr><tr><td>メール</td><td>✅</td><td>契約関連の通知先</td></tr><tr><td>ユーザー名</td><td>✅</td><td>オーナーアカウントのユーザー名（半角英数）</td></tr><tr><td>パスワード</td><td>✅</td><td>オーナー用パスワード（8 文字以上 + 英字 + 数字）</td></tr><tr><td>店舗数</td><td>✅</td><td>契約する店舗数（1 以上）</td></tr><tr><td>本部一括配信アドオン</td><td>—</td><td>チェックボックス（チェーン店のみ ON）</td></tr></tbody></table><ol start="4"><li><strong>【お申込み → Stripe 決済画面へ】</strong></li><li>Stripe Checkout 画面に遷移</li><li><strong>クレジットカード情報</strong> を入力 <ul><li>カード番号</li><li>有効期限</li><li>セキュリティコード</li></ul></li><li><strong>【申し込み】</strong></li><li><strong>30 日間無料トライアル開始</strong>（この時点ではまだ課金されない）</li><li>POSLA側で自動処理: <ul><li>テナント作成</li><li>店舗レコード作成（指定店舗数分）</li><li>オーナーアカウント作成</li><li>ウェルカムメール送信（ログイン情報付き）</li></ul></li><li>ウェルカムメール受信（通常 5 分以内）</li><li>メール内の <strong>ログイン URL</strong> からログイン → 運用開始</li></ol><h3 id="_7-1-2-トライアル期間中の注意" tabindex="-1">7-1-2. トライアル期間中の注意 <a class="header-anchor" href="#_7-1-2-トライアル期間中の注意" aria-label="Permalink to &quot;7-1-2. トライアル期間中の注意&quot;">​</a></h3><ul><li><strong>31 日目から自動で月額課金</strong> が開始される（Stripe が自動処理）</li><li>トライアル期間中でも全機能が使える</li><li>30 日以内にキャンセルすれば請求なし（7-5 参照）</li></ul><h2 id="_7-2-契約内容の確認" tabindex="-1">7-2. 契約内容の確認 <a class="header-anchor" href="#_7-2-契約内容の確認" aria-label="Permalink to &quot;7-2. 契約内容の確認&quot;">​</a></h2><h3 id="_7-2-1-stripe-customer-portal-を開く" tabindex="-1">7-2-1. Stripe Customer Portal を開く <a class="header-anchor" href="#_7-2-1-stripe-customer-portal-を開く" aria-label="Permalink to &quot;7-2-1. Stripe Customer Portal を開く&quot;">​</a></h3><p>Stripe の顧客ポータルで請求情報を確認できます。</p><ol><li>オーナーアカウントで管理画面を開く</li><li>上部タブ <strong>【決済設定】</strong> を開く</li><li><strong>【Customer Portal を開く】</strong> ボタン</li><li>新しいタブで Stripe のポータル画面が開く</li><li>以下が確認できる:</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td><strong>請求履歴</strong></td><td>過去の請求明細・PDF ダウンロード可</td></tr><tr><td><strong>次回請求日</strong></td><td>いつ次の課金があるか</td></tr><tr><td><strong>プラン詳細</strong></td><td>契約中のプラン・アドオン</td></tr><tr><td><strong>カード情報</strong></td><td>登録カードの確認・変更</td></tr><tr><td><strong>請求書ダウンロード</strong></td><td>各月の領収書を PDF で取得</td></tr></tbody></table><h3 id="_7-2-2-posla-管理画面での確認" tabindex="-1">7-2-2. POSLA 管理画面での確認 <a class="header-anchor" href="#_7-2-2-posla-管理画面での確認" aria-label="Permalink to &quot;7-2-2. POSLA 管理画面での確認&quot;">​</a></h3><p>一部情報はオーナー管理画面の【契約・プラン】タブでも確認できます。</p><ul><li>現在のプラン</li><li>次回請求予定額</li><li>店舗数</li><li>アドオン契約状況</li></ul><hr><h2 id="_7-3-本部一括配信アドオンの追加" tabindex="-1">7-3. 本部一括配信アドオンの追加 <a class="header-anchor" href="#_7-3-本部一括配信アドオンの追加" aria-label="Permalink to &quot;7-3. 本部一括配信アドオンの追加&quot;">​</a></h2><p>途中からアドオンを契約したい場合。</p><h3 id="_7-3-1-手順" tabindex="-1">7-3-1. 手順 <a class="header-anchor" href="#_7-3-1-手順" aria-label="Permalink to &quot;7-3-1. 手順&quot;">​</a></h3><ol><li>オーナー管理画面 → 【決済設定】タブ</li><li><strong>【アドオン管理】</strong> セクション</li><li><strong>「本部一括配信 (+¥3,000 / 月 / 店舗)」</strong> トグル <strong>ON</strong></li><li><strong>【Stripe Checkout で確定】</strong> ボタン</li><li>Stripe の確認画面で最終確定</li><li>アドオン契約が追加される</li><li>次回請求から料金が変わる（日割り計算あり）</li></ol><h3 id="_7-3-2-アドオン有効化後の変更" tabindex="-1">7-3-2. アドオン有効化後の変更 <a class="header-anchor" href="#_7-3-2-アドオン有効化後の変更" aria-label="Permalink to &quot;7-3-2. アドオン有効化後の変更&quot;">​</a></h3><ul><li>オーナー管理画面に <strong>【本部メニュー】</strong> タブが即座に出現</li><li>既存の店舗メニューデータは引き継がれる</li><li>店舗側ダッシュボードでは本部マスタ項目を店舗ごとに変更できない状態になる</li></ul><hr><h2 id="_7-4-解約の方法" tabindex="-1">7-4. 解約の方法 <a class="header-anchor" href="#_7-4-解約の方法" aria-label="Permalink to &quot;7-4. 解約の方法&quot;">​</a></h2><h3 id="_7-4-1-stripe-portal-経由で解約" tabindex="-1">7-4-1. Stripe Portal 経由で解約 <a class="header-anchor" href="#_7-4-1-stripe-portal-経由で解約" aria-label="Permalink to &quot;7-4-1. Stripe Portal 経由で解約&quot;">​</a></h3><ol><li>オーナー管理画面 → 【決済設定】 → <strong>【Customer Portal を開く】</strong></li><li>Stripe Portal 画面で <strong>【Cancel Plan】</strong> または <strong>【プランをキャンセル】</strong></li><li>理由を選択（任意）</li><li><strong>【キャンセルを確定】</strong></li><li>解約処理完了</li></ol><h3 id="_7-4-2-解約後の動き" tabindex="-1">7-4-2. 解約後の動き <a class="header-anchor" href="#_7-4-2-解約後の動き" aria-label="Permalink to &quot;7-4-2. 解約後の動き&quot;">​</a></h3><ul><li><strong>現在の請求期間末まで利用可能</strong>（例: 4/15 に解約 → 4/30 まで使える）</li><li>期間末で自動停止</li><li>データは <strong>30 日間保持</strong>（再契約時の復旧用）</li><li>30 日経過後に物理削除</li></ul><h3 id="_7-4-3-データのエクスポート" tabindex="-1">7-4-3. データのエクスポート <a class="header-anchor" href="#_7-4-3-データのエクスポート" aria-label="Permalink to &quot;7-4-3. データのエクスポート&quot;">​</a></h3><p>解約する前に、必要なデータは CSV でエクスポートしてください:</p><ul><li>メニュー: 【メニュー管理】 → 【CSV エクスポート】</li><li>注文履歴: 【レポート】 → 【注文履歴】 → CSV</li><li>スタッフ情報: 【スタッフ管理】 → エクスポート（将来対応）</li><li>売上レポート: 各レポートの CSV エクスポート</li></ul><p>解約後 30 日以内ならデータ持ち出しできます。31 日以降は不可。</p><hr><h2 id="_7-5-30-日無料トライアル中のキャンセル" tabindex="-1">7-5. 30 日無料トライアル中のキャンセル <a class="header-anchor" href="#_7-5-30-日無料トライアル中のキャンセル" aria-label="Permalink to &quot;7-5. 30 日無料トライアル中のキャンセル&quot;">​</a></h2><h3 id="_7-5-1-条件" tabindex="-1">7-5-1. 条件 <a class="header-anchor" href="#_7-5-1-条件" aria-label="Permalink to &quot;7-5-1. 条件&quot;">​</a></h3><ul><li>申込から <strong>30 日以内</strong> ならキャンセルで請求なし</li><li>31 日目以降にキャンセルすると、その月の料金は発生する（月割り / 日割り）</li></ul><h3 id="_7-5-2-手順" tabindex="-1">7-5-2. 手順 <a class="header-anchor" href="#_7-5-2-手順" aria-label="Permalink to &quot;7-5-2. 手順&quot;">​</a></h3><p>7-4 と同じ手順で Customer Portal から <strong>【Cancel】</strong>。期間末（31 日目）に自動停止。期間中は全機能使える（試用期間として）。</p><hr><h2 id="_7-6-よくある質問" tabindex="-1">7-6. よくある質問 <a class="header-anchor" href="#_7-6-よくある質問" aria-label="Permalink to &quot;7-6. よくある質問&quot;">​</a></h2><p><strong>Q1. プラン変更（アップグレード・ダウングレード）はできる？</strong></p><p>A1. <strong>単一プラン + アドオン構成なので「プラン変更」という概念はありません</strong>。変えられるのは以下のみ:</p><ul><li>店舗数（Stripe Subscription の quantity で自動）</li><li>本部一括配信アドオンの ON/OFF</li></ul><p><strong>Q2. 支払方法を変えたい</strong></p><p>A2. Stripe Customer Portal で <strong>【カード情報変更】</strong>。新しいカード情報を入力して保存。</p><p><strong>Q3. 領収書が欲しい</strong></p><p>A3. Stripe から自動発行メールが毎月の請求時に送信されます。また Customer Portal から過去の請求書 PDF を随時ダウンロード可能。</p><p><strong>Q4. 税務書類（インボイス対応）は？</strong></p><p>A4. インボイス対応は準備中です。現在は Stripe の請求書で代用してください。</p><p><strong>Q5. 複数の店舗を違うカードで決済したい</strong></p><p>A5. <strong>不可</strong>。POSLA では <strong>1 テナント = 1 カード登録</strong> の仕様です。同じテナント内の全店舗は 1 枚のカードで一括請求されます。</p><p><strong>Q6. 解約したら即データ消える？</strong></p><p>A6. <strong>30 日間は保持されます</strong>。この間に再契約すれば全データ復旧。30 日経過後は物理削除。</p><p><strong>Q7. 一時休業したい。契約を一時停止できる？</strong></p><p>A7. 現状「一時停止」機能はありません。解約 → 再契約の流れになります（30 日以内なら簡単に戻せる）。</p><p><strong>Q8. 月の途中で店舗を追加した。請求はどうなる？</strong></p><p>A8. Stripe が <strong>日割り計算</strong> します。その月の残り日数分の料金が次回請求に加算されます。</p><p><strong>Q9. クレジットカード以外で払いたい</strong></p><p>A9. 現状 Stripe 経由の <strong>クレジットカードのみ</strong>。銀行振込・請求書払いは非対応。</p><p><strong>Q10. Stripe アカウント持っていない / Stripe に直接登録したくない</strong></p><p>A10. Customer Portal を使わなくても、Stripe 側で自動的にカスタマーアカウントが作られます（ユーザー側の登録作業は不要）。</p><hr><h2 id="_7-7-契約周りのトラブルシューティング" tabindex="-1">7-7. 契約周りのトラブルシューティング <a class="header-anchor" href="#_7-7-契約周りのトラブルシューティング" aria-label="Permalink to &quot;7-7. 契約周りのトラブルシューティング&quot;">​</a></h2><h3 id="_7-7-1-請求できなかったとき" tabindex="-1">7-7-1. 請求できなかったとき <a class="header-anchor" href="#_7-7-1-請求できなかったとき" aria-label="Permalink to &quot;7-7-1. 請求できなかったとき&quot;">​</a></h3><p>Stripe がカード決済を試みて失敗した場合:</p><ol><li>自動的に 3 回リトライされる（日を置いて）</li><li>それでも失敗したら POSLA 運営に通知</li><li>アカウントが一時的に停止される可能性あり</li><li>オーナーのメールに通知が届く</li><li>対処: Customer Portal でカード情報を更新</li></ol><h3 id="_7-7-2-カードが期限切れ" tabindex="-1">7-7-2. カードが期限切れ <a class="header-anchor" href="#_7-7-2-カードが期限切れ" aria-label="Permalink to &quot;7-7-2. カードが期限切れ&quot;">​</a></h3><ol><li>期限切れの 30 日前にカスタマーからメール通知（Stripe から）</li><li>Customer Portal で新しいカードに更新</li><li>期限切れまで放置すると自動的に再試行失敗</li></ol><h3 id="_7-7-3-請求書の金額が合わない" tabindex="-1">7-7-3. 請求書の金額が合わない <a class="header-anchor" href="#_7-7-3-請求書の金額が合わない" aria-label="Permalink to &quot;7-7-3. 請求書の金額が合わない&quot;">​</a></h3><ol><li>Customer Portal で請求書 PDF をダウンロード</li><li>明細を確認（日割り計算が含まれていることが多い）</li><li>それでも合わない場合 <code>info@posla.jp</code> に連絡</li></ol><hr><h2 id="_7-8-契約書類" tabindex="-1">7-8. 契約書類 <a class="header-anchor" href="#_7-8-契約書類" aria-label="Permalink to &quot;7-8. 契約書類&quot;">​</a></h2><p>POSLA の契約は <strong>利用規約</strong> と <strong>プライバシーポリシー</strong> に同意することで成立します。</p><ul><li>利用規約: <code>https://eat.posla.jp/terms</code>（LP から参照可）</li><li>プライバシーポリシー: <code>https://eat.posla.jp/privacy</code></li><li>特定商取引法表記: 契約時の LP に記載</li></ul><hr><h2 id="_7-10-詳細は" tabindex="-1">7-10. 詳細は <a class="header-anchor" href="#_7-10-詳細は" aria-label="Permalink to &quot;7-10. 詳細は&quot;">​</a></h2><p>→ <a href="./../tenant/21-stripe-full.html">21 章 Stripe 決済の全設定</a></p><hr><h2 id="_7-11-次のページへ" tabindex="-1">7-11. 次のページへ <a class="header-anchor" href="#_7-11-次のページへ" aria-label="Permalink to &quot;7-11. 次のページへ&quot;">​</a></h2><p>→ <a href="./part8-troubleshooting.html">Part 8: トラブルシューティング</a></p>',98)])])}const c=r(o,[["render",e]]);export{u as __pageData,c as default};
